func:
let umidadeSolo =
    Number(flow.get("umidade_solo"));

let chuva24h =
    Number(flow.get("previsao_chuva"));

let temperatura =
    Number(flow.get("sensacao"));


msg.cidade = flow.get("cidade");

function normalizarCidade(cidade) {
    return cidade
        .trim()
        .normalize("NFD")                     
        .replace(/[\u0300-\u036f]/g, "")      
        .toLowerCase();
}

// Recria o mapa com chaves já normalizadas
const cidadeCultura = {
    "sao paulo": "milho",
    "campinas": "cafe",
    "sao jose dos campos": "algodao"
};

// Define a necessidade de água por cultura
const necessidadeAgua = {
    milho: 6,
    soja: 5,
    cafe: 4,
    cana: 7,
    tomate: 8,
    alface: 5,
    arroz: 9,
    feijao: 5,
    trigo: 4,
    algodao: 6
};

let cultura = cidadeCultura[normalizarCidade(msg.cidade)] || "milho";

// Salva no contexto para usar em outros nós
flow.set("cultura", cultura);
flow.set("necessidade_agua", necessidadeAgua[cultura]);

let mmIdeal =
    necessidadeAgua[cultura] || 5;

// AJUSTE TEMPERATURA

if (temperatura >= 35) {

    mmIdeal += 3;

} else if (temperatura >= 30) {

    mmIdeal += 2;

} else if (temperatura >= 25) {

    mmIdeal += 1;
}

// LÓGICA

let irrigar = false;

let motivo = "";

// SOLO MUITO SECO

if (umidadeSolo <= 25) {
    irrigar = true;
    motivo = "Solo extremamente seco.";

} else if (chuva24h >= mmIdeal) {          
    irrigar = false;
    motivo = "Previsão de chuva suficiente.";

} else if (umidadeSolo <= 45 && chuva24h < mmIdeal) {
    irrigar = true;
    motivo = "Baixa umidade e ausência de chuva.";

} else {
    irrigar = false;
    motivo = "Solo já úmido.";
}

// SAÍDA

flow.set("irrigacao", irrigar);

flow.set("necessidade_hidrica", mmIdeal);

msg.topic =
    "MACK/ComandoIrrigacao";

msg.payload = {

    irrigacao: irrigar,

    rele: irrigar
        ? "ON"
        : "OFF",

    dados: {

        cidade: msg.cidade,

        cultura: cultura,

        umidadeSolo: umidadeSolo,

        temperatura: temperatura,

        previsaoChuva: chuva24h,

        necessidadeHidrica: mmIdeal
    },

    mensagem: motivo,

    timestamp: new Date().toISOString()
};

node.warn(msg.payload);

return msg;

let data = msg.payload;

let moisture = data.moisture * 100;

flow.set(
    "umidade_solo",
    Number(moisture.toFixed(1))
);

flow.set(
    "temperatura_superficial",
    Number((data.t0 - 273.15).toFixed(2))
);

flow.set(
    "temperatura_10cm",
    Number((data.t10 - 273.15).toFixed(2))
);

node.warn({
    umidade_solo:
        flow.get("umidade_solo")
});

return msg;

let lista = msg.payload.list;

// Próximas 24h = 8 entradas de 3h
let proximas24h = lista.slice(0, 8);

let mmTotais = 0;
let probMaxima = 0;

proximas24h.forEach(item => {
    // Acumula mm reais previstos
    if (item.rain && item.rain["3h"]) {
        mmTotais += item.rain["3h"];
    }

    // Maior probabilidade do período
    if (item.pop > probMaxima) {
        probMaxima = item.pop;
    }
});

// Se não tem mm mas há chance significativa, estima
if (mmTotais === 0 && probMaxima >= 0.3) {
    mmTotais = probMaxima * 5;
}

flow.set("previsao_chuva", Number(mmTotais.toFixed(1)));
flow.set("prob_chuva", probMaxima);

node.warn({
    prob_chuva: `${(probMaxima * 100).toFixed(0)}%`,
    previsao_chuva: `${mmTotais.toFixed(1)}mm`
});

return msg;

// OUTRAS INFORMAÇÕES

let data = msg.payload;

flow.set(
    "sensacao",
    Number(data.main.feels_like.toFixed(2))
);

flow.set(
    "cidade",
    data.name
);

flow.set(
    "pais",
    data.sys.country
);

flow.set(
    "clima",
    data.weather[0].description
);

flow.set(
    "vento",
    Number(data.wind.speed.toFixed(2))
);

node.warn({

    cidade:
        flow.get("cidade"),

    pais:
        flow.get("pais"),

    sensacao:
        flow.get("sensacao"),

    clima:
        flow.get("clima"),

    vento:
        flow.get("vento")
});

return msg;

let timestampStr = msg.payload && msg.payload.timestamp;
let dataCompleta = "00/00/0000";
let horaCompleta = "00:00:00";
let dataObjeto = new Date();

if (timestampStr) {
    dataObjeto = new Date(timestampStr);
    let local = new Date(dataObjeto.getTime() - 3 * 60 * 60 * 1000);
    let d = local.toISOString().split("T");
    let partes = d[0].split("-");
    dataCompleta = `${partes[2]}/${partes[1]}/${partes[0]}`;
    horaCompleta = d[1].substring(0, 8);
}

msg.timestamp = dataObjeto;

msg.payload = [
    {
        temperatura: Number(flow.get("sensacao")),
        umidade_solo: Number(flow.get("umidade_solo")),
        previsao_chuva: Number(flow.get("previsao_chuva")),
        vento: Number(flow.get("vento")) || 0,
        irrigacao: flow.get("irrigacao") ? 1.0 : 0.0,
        necessidade_hidrica: Number(flow.get("necessidade_hidrica")),
        data_leitura: dataCompleta,
        hora_leitura: horaCompleta
    },
    {
        cidade: flow.get("cidade") || "Desconhecida",
        cultura: flow.get("cultura") || "Desconhecida", 
        clima: flow.get("clima") || "Desconhecido"
    }
];

return msg;

msg.cidade = flow.get("cidade"); 

msg.url =
  "https://api.openweathermap.org/data/2.5/forecast?q=" +
  encodeURIComponent(msg.cidade) +
  ",BR&units=metric&lang=pt_br&appid=3aa1dc2c08415f73fcbd5a09a705c0dc";

node.warn(msg.url);

return msg;

msg.cidade = flow.get("cidade");

msg.url =
  "https://api.openweathermap.org/data/2.5/weather?q=" +
  encodeURIComponent(msg.cidade) +
  ",BR&units=metric&lang=pt_br&appid=3aa1dc2c08415f73fcbd5a09a705c0dc";

node.warn(msg.url);

return msg;
